constexpr int sub(int a, int b) { return (a - b) % Mod; }

constexpr int mul(int a, int b) { return (int) ((long long) a * b % Mod); }

constexpr int fma(int a, int b, int c) { return (int) (((long long) a * b + c) % Mod); }

