using namespace std;

const int N = 1e5 + 5;

struct node{

    int flag,num,ii,mm;

};

node a1[N],a2[N],vis[N]={0};

int cmp(node x,node y){

    if(x.flag!=y.flag) return x.flag<y.flag;

    return x.num<y.num;

}

int cmp1(node x,node y){

    return x.ii<y.ii;

}

int main()

{

    int n,m;

    scanf("%d%d",&n,&m);

    for(int i=1;i<=m;i++){

        scanf("%d %d",&a1[i].flag,&a1[i].num);

        a2[i].ii=i;

        a2[i].flag=a1[i].flag;

        a2[i].num=a1[i].num;

    }

    sort(a2+1,a2+m+1,cmp);

    int f=a2[1].flag,ans=1;

    for(int i=1;i<=m;i++){

        if(f==a2[i].flag){

            a2[i].mm=ans++;

        }

        else{

            f=a2[i].flag;

            ans=1;

            a2[i].mm=ans++;



        }

    }

    sort(a2+1,a2+1+m,cmp1);

    for(int i=1;i<=m;i++){

        printf("%06d%06d\n",a2[i].flag,a2[i].mm);

    }

    return 0;

}

