#define s second

using namespace std;



typedef pair<pair<int,int>,pair<int,int> > P;



bool PC(P& f,P& s){return f.s.s<s.s.s;}



int main()

{

	int n,m,p,y;

	P a[100010];

	cin>>n>>m;

	for(int i=0;i<m;i++)

	{

		cin>>p>>y;

		a[i].f.f=p;

		a[i].f.s=y;

		a[i].s.f=0;

		a[i].s.s=i;

	}

	sort(a,a+m);

	p=a[0].f.f;

	y=0;

	for(int i=0;i<m;i++)

	{

		if(p!=a[i].f.f)p=a[i].f.f,y=0;

		a[i].s.f=++y;

	}

	sort(a,a+m,PC);

	for(int i=0;i<m;i++)printf("%012ld\n",(long)(a[i].f.f*1e6+a[i].s.f));

	return 0;

}

